var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"초광역터널 내부. 차원함선 코핀.","ENG":"Inside the hyperwide tunnel. Dimension ship Coffin.","TWN":"超廣域隧道內部，次元艦船科芬。","DEU":"Inside the hyperwide tunnel. Dimension ship Coffin.","FRA":"Inside the hyperwide tunnel. Dimension ship Coffin."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"오퍼레이터. 방금 탐지 된 이상 파장의 위치 분석은 어떻게 됐지?","JPN":"オペレーター、さっき探知された異常波長の位置分析の結果は？","ENG":"Operator. What's the analysis on the location of the anomalous wavelength we just detected?","TWN":"機務員，剛剛偵測到的異常波長分析位置結果如何？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"네...! 아주 잠깐 동안 나타났다가 사라지긴 했는데, 출처는 저희가 향하는 목적지가 분명합니다!","JPN":"はい……！　一瞬だけ現れて消えましたが、出所は私たちが向かっている目的地に違いありません！","ENG":"Ma'am...! It only appeared briefly before disappearing, but the source is definitely the destination we're heading toward!","TWN":"是……！雖然只出現了一瞬間就消失了，但來源確定是我們的目的地！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"파장의 유형은 어때? 침식파였어? 아니면 허수 에너지?","JPN":"波長のタイプは？　侵食波？　それとも虚数エネルギー？","ENG":"What about the wavelength type? Was it a Corruption ray? Or Imaginary Energy?","TWN":"波長類型呢？侵蝕波？還是虛空能量？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"둘 다 아니군요. 열람 가능한 관리국 데이터베이스에 따르면, 노르드나빅의 <color=#ffd34c>낙원문</color>이란 시설에서 사용되던 왜곡 파장 기술과 비슷합니다.","JPN":"どちらも違います。閲覧可能な管理局データベースによると、ノルドナビックの<color=#ffd34c>楽園の門</color>という施設で使用されていた歪曲波長技術に類似しています。","ENG":"Neither. According to accessible Administration database records, it's similar to the distortion wavelength technology used at a facility called <color=#ffd34c>Avalon's Gate</color> in Nordnavik.","TWN":"都不是。根據可以瀏覽的管理局資料庫，和諾爾德萊比<color=#ffd34c>樂園門</color>設施使用的扭曲波長技術很相似。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"침식체의 감지기관을 교란시키는 용도죠. 저도 직접 본 적은 없어서, 실제로 그렇게 작동하는진 모르겠지만요.","JPN":"侵食体の感知器官を撹乱させるためのものです。私も実際見たことはないので、本当にそう作動するかは分かりませんが。","ENG":"It's used to disrupt the detection organs of C.O.s. I've never seen it myself, so I can't be sure if it really works that way.","TWN":"那是用來干擾侵蝕體感知器官的。我也沒親眼見過，不確定實際上是不是這樣運作。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"이상하네. 마왕씩이나 되는 존재가... 그런 걸 쓰면서까지 침식체한테 숨을 필요가 있을까?","JPN":"おかしいな。魔王ともあろう存在が……そんなものを使ってまで侵食体から身を隠す必要がある？","ENG":"That's strange. A being on the level of a Demon Lord... would they really need to hide from C.O.s using something like that?","TWN":"真奇怪。像魔王那樣的存在……有必要用這種方式躲避侵蝕體嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"마왕의 왕좌 뿐만 아니라, 침식체가 아닌 존재가 있는 걸지도 모르지.","JPN":"魔王の玉座だけじゃなくて、侵食体じゃない存在がいるのかも。","ENG":"Maybe there are beings there that aren't C.O.s, not just the Demon Lord's throne.","TWN":"也許除了魔王的王座之外，那裡還有不是侵蝕體的存在。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"침식체가 아닌 존재?","JPN":"侵食体じゃない存在？","ENG":"Beings that aren't C.O.s?","TWN":"不是侵蝕體的存在？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하긴. 네헤모트와 싸우던 전장에도 문명의 흔적과 사람의 모습을 한 마왕군이 있었으니까요.","JPN":"まあ、ネヘモトと戦った戦場にも、文明の痕跡や人の姿をした魔王軍が存在していましたからね。","ENG":"Well, even on the battlefield where we fought Nehemoth, there were traces of civilization and Demon Lord forces that looked human.","TWN":"也是。之前和貝赫莫特戰鬥的戰場上，也有文明遺跡和外形像人的魔王軍。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"엑, 그 무시무시한 인형이랑 노래하는 괴물 말고도 뭐가 더 남았다고?","JPN":"げっ、あの恐ろしい人形とか歌う化け物の他にもまだ何かいるの？","ENG":"Ugh, don't tell me there's more than just that terrifying doll and the singing monster?","TWN":"欸？除了那個可怕的人偶和會唱歌的怪物，居然還有別的？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"필요하다면 싸우겠지만... 괴물도 아닌 사람 모습을 하고 있으면, 쉽지는 않겠네.","JPN":"必要なら戦うけど……化け物じゃなくて、人の見た目をしてるなら、簡単にいかないかもね。","ENG":"If we have to fight them, we will... But if they look human rather than monsters, it won't be easy.","TWN":"必要時當然會戰鬥……但如果對方看起來不是怪物而是人類，就沒那麼容易下手了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사람의 모습을 하고 있다고 해서 다 같은 편은 아닙니다.","JPN":"人の姿をしているからといって、皆が味方であるわけではありません。","ENG":"Just because something looks human doesn't mean it's on our side.","TWN":"就算外表是人類的，也不一定站在我們這一邊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"결국, 생김새가 아닌 입장의 차이가 적과 아군을 판가름하는 거니까요.","JPN":"結局、敵味方を区別するのは見た目ではなく、立場の違いなのですから。","ENG":"In the end, what determines allies and enemies isn't appearance, but where they stand.","TWN":"畢竟決定敵我關係的從來不是外表，而是立場。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"솔직히, 당신의 정체를 알고 있는 이상 쉽게 믿음을 주긴 힘들어.","JPN":"正直あなたの正体を知っている以上、簡単に信じることはできない。","ENG":"To be honest, it's hard to trust you after learning who you are.","TWN":"老實說，在已經知道你的身分的情況下，我很難百分百信任你。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내가 아는 다른 세계의 사람들은 모두 나에게 칼을 겨눈 적이었거든.","JPN":"私が知っている裏世界の住民は皆、私に刃を向けた敵だったから。","ENG":"The people I've met who came from other worlds were all enemies who tried to kill me.","TWN":"因為我認識的另一個世界的人都曾與我刀刃相向。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이해해요. 전 그냥 낯선 사람도 아니고, 당신들의 세계에 속하지 않은 외부의 존재이니까요.","JPN":"わかります。私はただの人でもなく、あなたたちの世界に属していない外部の存在ですから。","ENG":"I understand. I am not just a stranger, but an outsider who doesn't belong in your world.","TWN":"我能理解。我不僅是個陌生人，還是個不屬於你們的世界的存在。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그런데 말이야.","JPN":"でもさ。","ENG":"But...","TWN":"不過呢。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"한편으론 확인해보고 싶은 마음이 있어.","JPN":"一方では、確かめたい気持ちもある。","ENG":"A part of me wants to see.","TWN":"另一方面，我想親眼看看。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"당신 같은 다른 세계의 사람이 정말 우릴 위해서 싸워줄 수 있는지.","JPN":"あなたのような裏世界の住民が本当に私たちのために戦ってくれるのか。","ENG":"If people from other worlds, like yourself, can really fight for us.","TWN":"像你這樣來自另一個世界的人是否真的能為我們而戰。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"적이 아니라, 같은 목적을 바라보는 아군이 되어줄 수 있는지를 말이야.","JPN":"敵ではなく、同じ目的を持つ味方になってくれるのかを。","ENG":"If you can be an ally with a shared goal and not an enemy.","TWN":"我想確認我們是否能成為目標一致的友軍，而不是敵人。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"함께할 기회만 준다면, 증명해 보일게요.","JPN":"お伴させてもらえるのであれば、証明してみせます。","ENG":"If you give me a chance, I'll prove you right.","TWN":"如果給我機會，我會證明給你看。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신들의 세계와 제가 지켜야 할 사람을 위해서.","JPN":"あなたたちの世界と、私が守らなければならない人のために。","ENG":"I'll fight for this world and for the person that I must protect.","TWN":"為了你們的世界和我必須保護的人們。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"당신은 아직 더 성장해야 합니다. 그런 작은 이빨로는 아무도 잡아먹지 못해요.","JPN":" あなたはもっと成長しなければなりません。そんな小さな牙では誰も捕食できませんよ。","ENG":"You need to grow. You won’t be able to hunt down anyone with small teeth.","TWN":"你還得繼續成長。那麼小的獠牙連獵物都抓不住。"},"stage":{"bg":"MS_1113_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"어쩌면... 당신을 조금 더 일찍 만났다면...","JPN":"もしかしたら……あなたにもう少し早く出会っていれば……","ENG":"If only... If only I had met you sooner...","TWN":"劉米娜……或許……如果能早一點認識你……"},"stage":{"bg":"black","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"조금 더 이야기를 할 수 있었다면... 그랬다면...","JPN":"もう少し早く話ができていれば……もしそうだったら……","ENG":"If only we had more time to talk... then...","TWN":"如果能再多和你聊一聊……那樣的話……"},"stage":{"bg":"black","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};